diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..792e02585ec1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,55 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  // icmp (op X, C), X with |C| > 1 -> icmp X, 0
+  // icmp X, (op X, C) with |C| > 1 -> icmp X, 0
+  // where op is sdiv, udiv, lshr, or ashr
+  {
+    const APInt *C;
+    BinaryOperator *BO = nullptr;
+    Value *X = nullptr;
+    bool Swapped = false;
+    // Check for (op X, C) on LHS and X on RHS
+    if (BO0 && Op1 == BO0->getOperand(0) &&
+        match(BO0->getOperand(1), m_APIntAllowUndef(C))) {
+      BO = BO0;
+      X = Op1;
+      Swapped = true;
+    }
+    // Check for X on LHS and (op X, C) on RHS
+    if (!BO && BO1 && Op0 == BO1->getOperand(0) &&
+        match(BO1->getOperand(1), m_APIntAllowUndef(C))) {
+      BO = BO1;
+      X = Op0;
+      Swapped = false;
+    }
+    if (BO) {
+      bool Valid = false;
+      switch (BO->getOpcode()) {
+      case Instruction::SDiv:
+        // Valid for |C| > 1, i.e., not 0, 1, or -1
+        Valid = !C->isZero() && !C->isOne() && !C->isAllOnes();
+        break;
+      case Instruction::UDiv:
+        // Valid for C > 1 (unsigned), i.e., not 0 or 1
+        Valid = !C->isZero() && !C->isOne();
+        break;
+      case Instruction::LShr:
+      case Instruction::AShr:
+        // Valid for C > 0
+        Valid = !C->isZero();
+        break;
+      default:
+        break;
+      }
+      if (Valid && (I.isSigned() || I.isEquality())) {
+        CmpInst::Predicate NewPred =
+            Swapped ? I.getSwappedPredicate() : Pred;
+        return new ICmpInst(NewPred, X,
+                            ConstantInt::getNullValue(X->getType()));
+      }
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

